						failureThreshold: 3
						httpGet: {
							path:   "/livez"
							port:   "https"
							scheme: "HTTPS"
						}
						initialDelaySeconds: 0
						periodSeconds:       10
					}
					name: "metrics-server"
					ports: [{
						containerPort: 10250
						name:          "https"
						protocol:      "TCP"
					}]
					readinessProbe: {
						failureThreshold: 3
						httpGet: {
							path:   "/readyz"
							port:   "https"
							scheme: "HTTPS"
						}
						initialDelaySeconds: 20
						periodSeconds:       10
					}
					resources: requests: {
						cpu:    "100m"
						memory: "200Mi"
					}
					securityContext: {
						allowPrivilegeEscalation: false
						capabilities: drop: ["ALL"]
						readOnlyRootFilesystem: true
						runAsNonRoot:           true
						runAsUser:              1000
						seccompProfile: type: "RuntimeDefault"
					}
					volumeMounts: [{
						mountPath: "/tmp"
						name:      "tmp"
					}]
				}]
				priorityClassName:  "system-cluster-critical"
				serviceAccountName: "metrics-server"
				volumes: [{
					emptyDir: {}
					name: "tmp"
				}]
			}
		}
	}
}
